// ─── Parse Telegram message & buffer album photos ────────────────────────
const trigger = $('Webhook Trigger').first();
const body = trigger.json.body;
const msg = body.message || {};
const text = (msg.text || msg.caption || '').trim();
const chatId = msg.chat?.id;
const msgId = msg.message_id;
const mediaGroupId = msg.media_group_id || null;
const OPENCODE_URL = 'http://opencode-proxy:3284';

if (mediaGroupId) {
  const photos = msg.photo || [];
  let fileId = photos.length > 0 ? photos[photos.length - 1].file_id : null;
  if (msg.document?.mime_type?.startsWith('image/')) fileId = msg.document.file_id;
  if (fileId) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: `${OPENCODE_URL}/media-group/add`,
        body: { mediaGroupId, fileId },
        json: true
      });
    } catch (e) {}
  }
}

const photoFileIds = [];
const photos = msg.photo || [];
if (photos.length > 0) photoFileIds.push(photos[photos.length - 1].file_id);
if (msg.document?.mime_type?.startsWith('image/')) photoFileIds.push(msg.document.file_id);

return [{ json: { chatId, msgId, text, mediaGroupId, photoFileIds, hasPhoto: photoFileIds.length > 0 } }];

// ─── Session Manager ───────────────────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const { chatId, text } = $json;

let sessionId = 'none';
let responseText = '';

try {
  if (text === '/new') {
    const result = await this.helpers.httpRequest({ method: 'POST', url: `${OPENCODE_URL}/session/clear`, body: { chatId }, json: true });
    sessionId = result.sessionId || 'none';
    responseText = result.message || '새로운 대화를 시작합니다.';
  } else {
    const result = await this.helpers.httpRequest({ method: 'GET', url: `${OPENCODE_URL}/session?chatId=${chatId}`, json: true });
    sessionId = result.sessionId || 'none';
  }
} catch (e) {}

return [{ json: { ...$json, sessionId: sessionId, displaySessionId: sessionId.replace(/^ses_/g, ''), responseText } }];

// ─── Route by Command or LLM Intent ──────────────────────────────────────────
const { text, hasPhoto } = $json;
const ROUTER_URL = 'http://router:3287';

try {
  const result = await this.helpers.httpRequest({
    method: 'POST', 
    url: `${ROUTER_URL}/router/intent`, 
    body: { message: text, hasPhoto }, 
    json: true 
  });

  const intent = result.intent || 'general';
  const routeMap = { 'blog': 'blog', 'email': 'email', 'stock': 'stock' };
  const finalRoute = routeMap[intent] || 'opencode';

  // IMPORTANT: Only extract SAFE fields from router response.
  // Do NOT spread ...result — it contains sessionId/text/formattedText
  // from the router's internal OpenCode call, which would overwrite
  // the user's real session data.
  const safeFields = {};
  if (result.topic) safeFields.topic = result.topic;
  if (result.receiver) safeFields.receiver = result.receiver;
  if (result.query) safeFields.query = result.query;
  if (result.subIntent) safeFields.subIntent = result.subIntent;

  return [{ json: { ...$json, route: finalRoute, message: text, intent, ...safeFields } }];
} catch (e) {
  return [{ json: { ...$json, route: 'opencode', message: text } }];
}

