// ─── Run OpenCode ────────────────────────────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const routeData = $('Route by Command').first().json;
const { chatId, msgId, message, intent, responseText, sessionId } = routeData;

// Handle /new response
if (responseText) return [{ json: { chatId, msgId, formattedText: responseText, sessionId } }];

try {
  const result = await this.helpers.httpRequest({
    method: 'POST', url: `${OPENCODE_URL}/run`, 
    body: { prompt: message, chatId: String(chatId), sessionId, intent }, 
    json: true, timeout: 300000
  });
  return [{ json: { chatId, msgId, formattedText: result.formattedText, sessionId: result.sessionId || sessionId } }];
} catch (e) {
  return [{ json: { chatId, msgId, formattedText: `❌ 오류: ${e.message}`, sessionId } }];
}

