// ─── Generate & Send AI Email (Modularized) ─────────────────────────────────
const EMAIL_PROXY_URL = 'http://email-proxy:3288';
const routeData = $('Route by Command').first().json;
const { chatId, msgId, receiver, query, sessionId } = routeData;

try {
  const result = await this.helpers.httpRequest({
    method: 'POST', 
    url: `${EMAIL_PROXY_URL}/send-ai-email`, 
    body: { query, receiver, chatId: String(chatId), sessionId }, 
    json: true, timeout: 180000
  });
  return [{ json: { chatId, msgId, formattedText: result.formattedText, sessionId: result.sessionId || sessionId } }];
} catch (e) {
  return [{ json: { chatId, msgId, formattedText: `❌ 이메일 오류: ${e.message}`, sessionId } }];
}
